var $bm_rt;
var n = thisComp.layer('CTRL').effect('Alerts')('Slider').value;
n = Math.round(n);
var sign = n < 0 ? '-' : '';
var str = Math.abs(n).toString();
var out = '';
var count = 0;
for (var i = str.length - 1; i >= 0; i--) {
    out = $bm_sum(str.charAt(i), out);
    count++;
    if (count % 3 === 0 && i !== 0)
        out = $bm_sum(',', out);
}
$bm_rt = $bm_sum(sign, out);

